#!/usr/bin/env bash
# AGY Agent Tools self-contained installer

set -e

echo -e "\033[1;36m⚡ Installing AGY Download Monitor & Tools...\033[0m"

# Create folders
mkdir -p "$HOME/Documents/agy-agent/bin"
mkdir -p "$HOME/Documents/agy-agent/chats"
mkdir -p "$HOME/Documents/agy-agent/downloads/active"
mkdir -p "$HOME/Documents/agy-agent/logs"

# Write embedded files
echo "Extracting tools..."

echo "  -> agy-monitor"
cat << 'EOF' | base64 -d > "$HOME/Documents/agy-agent/bin/agy-monitor"
IyEvYmluL2Jhc2gKIyBBR1kgRG93bmxvYWQgTW9uaXRvciBsYXVuY2hlcgojIFVzYWdlOiBhZ3ktbW9uaXRvciA8bG9nZmlsZT4gWy0tdHlwZSBhcHR8cGlwfGdlbmVyaWNdCgpTQ1JJUFRfRElSPSIkKGNkICIkKGRpcm5hbWUgIiR7QkFTSF9TT1VSQ0VbMF19IikiICYmIHB3ZCkiCmV4ZWMgcHl0aG9uMyAiJFNDUklQVF9ESVIvYWd5LW1vbml0b3IucHkiICIkQCIK
EOF


echo "  -> agy-monitor.py"
cat << 'EOF' | base64 -d > "$HOME/Documents/agy-agent/bin/agy-monitor.py"

EOF


echo "  -> agy-run-dl"
cat << 'EOF' | base64 -d > "$HOME/Documents/agy-agent/bin/agy-run-dl"

EOF


echo "  -> agy-save-chat"
cat << 'EOF' | base64 -d > "$HOME/Documents/agy-agent/bin/agy-save-chat"

EOF


echo "  -> agy-save-chat.py"
cat << 'EOF' | base64 -d > "$HOME/Documents/agy-agent/bin/agy-save-chat.py"

EOF


# Permissions
chmod +x "$HOME/Documents/agy-agent/bin"/*

# Configure PATH
BASHRC="$HOME/.bashrc"
if [ -f "$BASHRC" ]; then
    if ! grep -q "agy-agent/bin" "$BASHRC"; then
        echo "Adding agy-agent to PATH in ~/.bashrc..."
        echo -e '\n# AGY Agent tools\nexport PATH="$HOME/Documents/agy-agent/bin:$PATH"' >> "$BASHRC"
        echo -e "\033[1;32m✓ PATH configured. Please run 'source ~/.bashrc' or open a new terminal.\033[0m"
    else
        echo "PATH is already configured."
    fi
fi

echo -e "\033[1;32m✓ Installation successful!\033[0m"
